const raw = $input.first().json.message?.content || $input.first().json.response || '';
let qc;
try {
  const match = raw.match(/```json\n([\s\S]*?)\n```/) || raw.match(/(\{[\s\S]*\})/);
  qc = JSON.parse(match ? (match[1] || match[0]) : raw);
  if (typeof qc.approved !== 'boolean') throw new Error('approved must be boolean');
} catch(e) {
  qc = { approved: false, average_score: 0, rejection_reason: 'QC parse failure', scores: {}, parse_error: true };
}
return [{ json: qc }];

const qc = $('✅ Parse & Validate QC').item.json;
const topic = $('✅ Parse & Validate Topic').item.json;
const assemble = $('🔧 Assemble Final Article').item.json;
const config = $('⚙️ Load Config').item.json;
const pkg = $('📋 Parse Prompt Package').item.json;

const fallbacks = [];
if (pkg.parse_error) fallbacks.push('agent_0');
if (topic.status === 'fallback_topic' || topic.error) fallbacks.push('agent_1');
if (qc.parse_error) fallbacks.push('agent_5');

const rejectionReasons = qc.scores && Object.keys(qc.scores).length
  ? JSON.stringify(qc.scores)
  : (qc.rejection_reason || 'QC rejected');
const now = new Date();
return [{ json: {
  date: now.toISOString().slice(0, 10),
  topic: topic.topic || '',
  primary_keyword: topic.primary_keyword || '',
  qc_score: qc.average_score != null ? qc.average_score : 0,
  rejection_reasons: rejectionReasons,
  word_count: assemble.word_count != null ? assemble.word_count : 0,
  agent_fallbacks_used: JSON.stringify(fallbacks),
  run_timestamp: now.toISOString()
}}];

const topic = $('✅ Parse & Validate Topic').item.json;
const inject = $('💉 Inject Approved Topic').item.json;
const useApproved = inject.use_approved_topic === true;
const rowNum = topic._row != null ? topic._row : null;
if (!useApproved || rowNum == null) {
  return [{ json: { skip_backlog_update: true } }];
}
return [{ json: { Row_Number: rowNum, status: 'rejected', Status: 'rejected' } }];

const topic = $('✅ Parse & Validate Topic').item.json;
const keyword = topic.primary_keyword || topic.topic || 'productivity';
const queries = [
  keyword,
  keyword.split(' ').slice(0,2).join(' '),
  topic.secondary_keywords?.[0] || 'business success'
];
return [{ json: { queries, primary_query: queries[0] }}];

let imageUrl = null;
let imageAlt = $('✅ Parse & Validate Topic').item.json.primary_keyword || 'article image';

// Try Pexels first
try {
  const pexels = $('📸 Search Pexels').item.json;
  if (pexels.photos && pexels.photos.length > 0) {
    imageUrl = pexels.photos[0].src.large || pexels.photos[0].src.original;
  }
} catch(e) {}

// Fallback to Pixabay
if (!imageUrl) {
  try {
    const pixabay = $('📸 Search Pixabay (Fallback)').item.json;
    if (pixabay.hits && pixabay.hits.length > 0) {
      imageUrl = pixabay.hits[0].largeImageURL || pixabay.hits[0].webformatURL;
    }
  } catch(e) {}
}

const needsAI = !imageUrl;
return [{ json: { image_url: imageUrl, image_alt: imageAlt, needs_ai_image: needsAI }}];

const mediaResponse = $input.first().json;
// WordPress returns the media object with id field
const mediaId = mediaResponse.id || null;
const mediaUrl = mediaResponse.source_url || mediaResponse.guid?.rendered || '';
const imageAlt = $('🔀 Select Best Image').item.json.image_alt || '';

return [{ json: { media_id: mediaId, media_url: mediaUrl, image_alt: imageAlt }}];

try {
  const $json = $input.first().json;
  const id = $json.id != null ? $json.id : '';
  const link = $json.link || $json.url || '';
  return [{ json: { id, link, status: 'published' } }];
} catch(e) {
  return [{ json: { id: '', link: '', status: 'publish_failed' } }];
}

const pkg = $('📋 Parse Prompt Package').item.json;
const topic = $('✅ Parse & Validate Topic').item.json;
const article = $('🔧 Assemble Final Article').item.json;
const qc = $('✅ Parse & Validate QC').item.json;
let wp = { id: '', link: '', url: '', status: 'publish_failed' };
try {
  wp = $('🔗 Capture WP Post Data').item.json;
} catch(e) {}

const errorAgents = [];
if (pkg.parse_error) errorAgents.push('agent_0');
if (topic.parse_error || topic.status === 'fallback_topic') errorAgents.push('agent_1');
if (article.parse_error) errorAgents.push('agent_4');
if (qc.parse_error) errorAgents.push('agent_5');

const wpUrl = wp.link || wp.url || '';
const wpId = wp.id != null ? String(wp.id) : '';
const publishFailed = !wpUrl && (wp.status === 'publish_failed' || !wp.id);

const now = new Date();
const row = {
  date: now.toISOString().slice(0, 10),
  title: article.title || topic.topic || '',
  primary_keyword: topic.primary_keyword || '',
  wp_url: wpUrl,
  wp_post_id: wpId,
  word_count: article.word_count || 0,
  status: publishFailed ? 'publish_failed' : 'published',
  parse_error: errorAgents.length > 0,
  parse_error_agents: JSON.stringify(errorAgents),
  qc_score: qc.average_score != null ? qc.average_score : '',
  affiliate_ctas: article.affiliate_ctas != null ? article.affiliate_ctas : 0,
  run_timestamp: now.toISOString()
};
return [{ json: row }];

// Called from Approval Poller: approved_topic may be passed in
// Called standalone: approved_topic is absent, use Reddit data
const approved = $('⚡ Entry Override')?.item?.json?.approved_topic || null;
const context  = $('🔧 Build Research Context').item.json;

return [{ json: {
  ...context,
  approved_topic:      approved,
  use_approved_topic:  !!approved
}}];

